{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyNM21kpsrkenSj+cJD7WAqN"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"markdown","source":["**Import Libraries**"],"metadata":{"id":"Ah7zga8PEfG4"}},{"cell_type":"code","source":["import pandas as pd\n","import matplotlib.pyplot as plt\n","from sklearn.cluster import KMeans, DBSCAN, AgglomerativeClustering\n","from sklearn.preprocessing import StandardScaler\n","from sklearn.impute import SimpleImputer\n","from scipy.cluster.hierarchy import dendrogram, linkage"],"metadata":{"id":"WQiuVQwzEhNZ","executionInfo":{"status":"ok","timestamp":1758908157553,"user_tz":-330,"elapsed":7,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":13,"outputs":[]},{"cell_type":"markdown","source":["**Load Data**"],"metadata":{"id":"HvIey8aKEiej"}},{"cell_type":"code","source":["file_path = 'cosmetics_fraud_2025.csv'\n","data = pd.read_csv(file_path)"],"metadata":{"id":"37x_qxzTEj0R","executionInfo":{"status":"ok","timestamp":1758908161241,"user_tz":-330,"elapsed":12,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":14,"outputs":[]},{"cell_type":"markdown","source":["**Select relevant numeric columns & Handle missing values**"],"metadata":{"id":"V6c955HsEmnq"}},{"cell_type":"code","source":["numeric_cols = ['Customer_Age', 'Purchase_Amount', 'Footfall_Count']\n","data_numeric = data[numeric_cols]\n","imputer = SimpleImputer(strategy='mean')\n","data_imputed = pd.DataFrame(imputer.fit_transform(data_numeric), columns=numeric_cols)"],"metadata":{"id":"s52sj7o0EpME","executionInfo":{"status":"ok","timestamp":1758908162519,"user_tz":-330,"elapsed":6,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":15,"outputs":[]},{"cell_type":"markdown","source":["**Normalize data**"],"metadata":{"id":"DDm4XxPiEub6"}},{"cell_type":"code","source":["scaler = StandardScaler()\n","data_scaled = pd.DataFrame(scaler.fit_transform(data_imputed), columns=numeric_cols)"],"metadata":{"id":"joGcVSiwEw4W","executionInfo":{"status":"ok","timestamp":1758908165291,"user_tz":-330,"elapsed":1,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":16,"outputs":[]},{"cell_type":"markdown","source":["**K-means clustering**"],"metadata":{"id":"CrBpnxz1Ez2R"}},{"cell_type":"code","source":["kmeans = KMeans(n_clusters=5, random_state=42)\n","kmeans_labels = kmeans.fit_predict(data_scaled)"],"metadata":{"id":"NDvVg_mWE1Q9","executionInfo":{"status":"ok","timestamp":1758908179489,"user_tz":-330,"elapsed":12,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":17,"outputs":[]},{"cell_type":"markdown","source":["**Agglomerative clustering**"],"metadata":{"id":"lQdzN1CIE307"}},{"cell_type":"code","source":["agglo = AgglomerativeClustering(n_clusters=5)\n","agglo_labels = agglo.fit_predict(data_scaled)"],"metadata":{"id":"CscplgCuE4mY","executionInfo":{"status":"ok","timestamp":1758908193410,"user_tz":-330,"elapsed":100,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":18,"outputs":[]},{"cell_type":"markdown","source":["**DBSCAN clustering**"],"metadata":{"id":"0WMtTkfIE68U"}},{"cell_type":"code","source":["dbscan = DBSCAN(eps=0.5, min_samples=5)\n","dbscan_labels = dbscan.fit_predict(data_scaled)"],"metadata":{"id":"pggbXpQHE7V3","executionInfo":{"status":"ok","timestamp":1758908197859,"user_tz":-330,"elapsed":41,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":19,"outputs":[]},{"cell_type":"markdown","source":["**Add cluster labels to dataframe**"],"metadata":{"id":"cp-ENw3fE_iH"}},{"cell_type":"code","source":["results = data_scaled.copy()\n","results['kmeans_cluster'] = kmeans_labels\n","results['agglo_cluster'] = agglo_labels\n","results['dbscan_cluster'] = dbscan_labels"],"metadata":{"id":"n_8V8RpAFEub","executionInfo":{"status":"ok","timestamp":1758908209102,"user_tz":-330,"elapsed":4,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}}},"execution_count":20,"outputs":[]},{"cell_type":"markdown","source":["**Plot function to visualize clustering results**"],"metadata":{"id":"lWGVM7krFHkz"}},{"cell_type":"code","source":["def plot_clusters(data, labels, title, ax):\n","    scatter = ax.scatter(data.iloc[:, 0], data.iloc[:, 1], c=labels, cmap='tab10', alpha=0.6)\n","    ax.set_xlabel(data.columns[0])\n","    ax.set_ylabel(data.columns[1])\n","    ax.set_title(title)\n","    plt.legend(*scatter.legend_elements(), title=\"Clusters\")\n","\n","# Visualize clusters for K-means, DBSCAN, Agglomerative\n","fig, axs = plt.subplots(1, 3, figsize=(18, 5))\n","plot_clusters(data_scaled, kmeans_labels, 'K-means Clustering', axs[0])\n","plot_clusters(data_scaled, dbscan_labels, 'DBSCAN Clustering', axs[1])\n","plot_clusters(data_scaled, agglo_labels, 'Agglomerative Clustering', axs[2])\n","plt.tight_layout()\n","plt.show()"],"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":527},"id":"kS8uOmGCFISo","executionInfo":{"status":"ok","timestamp":1758908220466,"user_tz":-330,"elapsed":960,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}},"outputId":"ba4f6aa4-108d-4402-d916-0e211880ade0"},"execution_count":21,"outputs":[{"output_type":"display_data","data":{"text/plain":["<Figure size 1800x500 with 3 Axes>"],"image/png":"\n"},"metadata":{}}]},{"cell_type":"markdown","source":["**Generate Dendogram for Agglomerative**"],"metadata":{"id":"k59AlTCaGYz_"}},{"cell_type":"code","source":["linked = linkage(data_scaled, method='ward')\n","plt.figure(figsize=(15, 8))\n","dendrogram(linked,\n","           orientation='top',\n","           distance_sort='descending',\n","           show_leaf_counts=False)\n","plt.title('Agglomerative Clustering Dendrogram')\n","plt.xlabel('Sample index')\n","plt.ylabel('Distance')\n","plt.show()"],"metadata":{"id":"3237hpsQGdTz","executionInfo":{"status":"ok","timestamp":1758908252703,"user_tz":-330,"elapsed":5572,"user":{"displayName":"ATHARVA LOTANKAR","userId":"17963573814870062971"}},"outputId":"b460ae7a-99d8-43d8-f742-a4fc2071e23b","colab":{"base_uri":"https://localhost:8080/","height":485}},"execution_count":22,"outputs":[{"output_type":"display_data","data":{"text/plain":["<Figure size 1500x800 with 1 Axes>"],"image/png":"\n"},"metadata":{}}]}]}